// MINIMAL DIAGNOSTIC LAYOUT
// This strips ALL providers, ALL context, ALL side-effects.
// Goal: determine if the crash is in the root layout providers
// or in expo-router/Expo config itself.
//
// If this screen shows on the phone → crash is in a provider.
// If this still blue-screens → crash is in Expo/Metro/config.

import { Stack } from "expo-router";
import { StatusBar } from "expo-status-bar";
import { StyleSheet, View, Text } from "react-native";
import React from "react";

// Re-export expo-router's ErrorBoundary
export { ErrorBoundary } from "expo-router";

export default function RootLayout() {
  return (
    <>
      <StatusBar style="light" />
      <Stack
        screenOptions={{
          headerShown: false,
          contentStyle: { backgroundColor: "#0A0A0F" },
        }}
      >
        <Stack.Screen name="(tabs)" options={{ headerShown: false }} />
        <Stack.Screen name="admin" options={{ headerShown: false }} />
        <Stack.Screen name="ivx" options={{ headerShown: false }} />
        <Stack.Screen name="property" options={{ headerShown: false }} />
        <Stack.Screen name="landing" options={{ headerShown: false }} />
        <Stack.Screen name="login" options={{ headerShown: false }} />
        <Stack.Screen name="signup" options={{ headerShown: false }} />
        <Stack.Screen name="modal" options={{ presentation: "modal" }} />
      </Stack>
    </>
  );
}

